export const LogoIcon3D: React.FC<{ className?: string, mode?: 'full' | 'top' | 'mid' | 'bot' }> = ({ className, mode = 'full' }) => {
    return (
        <svg viewBox="0 0 100 100" className={className} fill="none" xmlns="http://www.w3.org/2000/svg">
            <defs>
                <linearGradient id="pix-grad-master" x1="0%" y1="0%" x2="100%" y2="100%">
                    <stop offset="0%" stopColor="#157AFF" />
                    <stop offset="100%" stopColor="#4FE6D0" />
