                <linearGradient id="surface-shine-master" x1="0%" y1="0%" x2="0%" y2="100%">
                    <stop offset="0%" stopColor="white" stopOpacity="0.9" />
                    <stop offset="100%" stopColor="white" stopOpacity="0.2" />
                </linearGradient>

                <filter id="inner-glow-master" x="-20%" y="-20%" width="140%" height="140%">
                    <feGaussianBlur stdDeviation="1.5" result="blur" />
                    <feComposite in="SourceGraphic" in2="blur" operator="over" />
                </filter>
            </defs>

            {/* BOTTOM LAYER */}
            {(mode === 'full' || mode === 'bot') && (
                <path 
                    d="M50 85C32 77 18 69 18 62C18 55 32 47 50 39C68 47 82 55 82 62C82 69 68 77 50 85Z" 
                    fill="#051024" 
                    fillOpacity="0.5"
                />
            )}

            {/* MIDDLE LAYER (Glass/Cyan) */}
            {(mode === 'full' || mode === 'mid') && (
                <g filter="url(#inner-glow-master)">
                    <path 
                        d="M50 72L18 56L50 40L82 56L50 72Z" 
                        fill="url(#pix-grad-master)" 
                        fillOpacity="0.45" 
                    />
                    <path d="M18 56V61C18 61 36 70 50 72C64 70 82 61 82 61V56C82 56 64 66 50 68C36 66 18 56 18 56Z" fill="url(#pix-grad-master)" fillOpacity="0.7" />
                </g>
            )}

            {/* TOP LAYER (Solid/White) */}
            {(mode === 'full' || mode === 'top') && (
                <g>
                    <path 
                        d="M50 54L18 38L50 22L82 38L50 54Z" 
                        fill="white" 
                    />
                    <path 
                        d="M50 54L18 38L50 22L82 38L50 54Z" 
